params.script:
// Script Template: condition_group
// 入力モジュールの出力値をグループ番号に分類（多段分岐用）
// プレースホルダー: OpenAI_新規_診療科判定 = 入力元モジュール名（OpenAI モジュール）
// プレースホルダー: {"循環器内科": "1", "脳神経内科": "1", "呼吸器内科": "1", "メンタルヘルス": "1", "代謝内分泌内科": "1", "感染症科": "1", "呼吸器外科": "1", "小児科": "1"} = 値→グループ番号の JSON オブジェクト
// プレースホルダー: 2 = マッピングに該当しない場合のデフォルトグループ番号
// 出力: グループ番号文字列（"1", "2", ... "10"）

var input = $runner.getModuleResult("OpenAI_新規_診療科判定");
var mapping = {"循環器内科": "1", "脳神経内科": "1", "呼吸器内科": "1", "メンタルヘルス": "1", "代謝内分泌内科": "1", "感染症科": "1", "呼吸器外科": "1", "小児科": "1"};
var group = mapping[input];
if (!group) { group = "2"; }
$runner.setResult(group);
